import { Area, LinePath } from '@visx/shape';
import { LinePathProps } from '@visx/shape/lib/shapes/LinePath';
import { AddSVGProps } from '@visx/shape/lib/types';

import { useId } from '../../../../../core/hooks/useId.js';
import { ThresholdBrightnessFilter } from '../ThresholdBrightnessFilter.js';

/** @internal */
export interface ThresholdIndicatorData {
  x0: number;
  x1: number;
  y0: number;
  y1: number;
}

/** @internal */
export interface ThresholdIndicatorProps {
  data: ThresholdIndicatorData[];
  color: string;
  isActive?: boolean;
  strokeOnly?: boolean;
}

/** @internal */
export const ThresholdIndicator = (props: ThresholdIndicatorProps) => {
  const id = useId();

  const { data, color, isActive = false, strokeOnly = false } = props;

  if (data.length === 0) {
    return null;
  }

  const opacity = isActive ? 0.2 : 0.1;
  const strokeWidth = isActive || strokeOnly ? 1 : 0;
  const strokeDasharray = !isActive && strokeOnly ? '3,2' : '0,0';
  const lineProps: AddSVGProps<
    LinePathProps<ThresholdIndicatorData>,
    SVGPathElement
  > = {
    data,
    stroke: color,
    strokeWidth,
    strokeDasharray,
  };
  const brightnessFilterId = `threshold-indicator-${id}`;

  return (
    <>
      <ThresholdBrightnessFilter id={brightnessFilterId} />
      <LinePath<ThresholdIndicatorData>
        {...lineProps}
        role="graphics-symbol"
        aria-label="threshold indicator line 0"
        x={(d) => d.x0}
        y={(d) => d.y0}
      />
      {!strokeOnly && (
        <Area<ThresholdIndicatorData>
          data={data}
          role="graphics-symbol"
          aria-label="threshold indicator area"
          x0={(d) => d.x0}
          x1={(d) => d.x1}
          y0={(d) => d.y0}
          y1={(d) => d.y1}
          fill={color}
          opacity={opacity}
          filter={isActive ? `url(#${brightnessFilterId})` : undefined}
        />
      )}
      <LinePath<ThresholdIndicatorData>
        {...lineProps}
        role="graphics-symbol"
        aria-label="threshold indicator line 1"
        x={(d) => d.x1}
        y={(d) => d.y1}
      />
    </>
  );
};
